import sqlite3
import threading

class FileAccessControl:
    def __init__(self, db_path):
        self.db_path = db_path
        self.lock = threading.Lock()

    def _connect_db(self):
        return sqlite3.connect(self.db_path)

    def _check_permission(self, user_id, file_id):
        conn = self._connect_db()
        cursor = conn.cursor()
        cursor.execute("SELECT access_level FROM permissions WHERE user_id = ? AND file_id = ?", (user_id, file_id))
        result = cursor.fetchone()
        conn.close()
        return result is not None and result[0] == 'read'

    def read_file(self, user_id, file_id, file_path):
        with self.lock:
            if not self._check_permission(user_id, file_id):
                raise PermissionError("User does not have permission to read the file.")
            with open(file_path, 'r') as file:
                return file.read()

